### 9.2.2 In-Memory Data Structures

```typescript
// Imported data
interface FleetState {
  trains: Train[];
  pmHistory: PMHistory[];
  pmRules: PMRule[];
}

interface Train {
  trainNumber: string;
  fleetCode: string;
  currentMileageKm: number;
  commissioningDate: Date;
  // Calculated
  estimatedDailyKm: number;
  confidence: 'HISTORICAL' | 'ESTIMATED';
}

interface PMHistory {
  trainNumber: string;
  pmCode: string;
  completionDate: Date;
  mileageAtCompletion: number;
}

interface PMRule {
  fleetCode: string;
  pmCode: string;
  intervalKm: number;
  intervalMonths: number | null;
  durationDays: number;
  estimatedHours: number;
  satisfiesCodes: string[];
}

// Projected data
interface ProjectedPM {
  id: string;  // Generated UUID
  trainNumber: string;
  pmCode: string;
  projectedDate: Date;
  projectedMileageKm: number;
  triggerType: 'MILEAGE' | 'TIME';
  confidence: 'HISTORICAL' | 'ESTIMATED';
  durationDays: number;
  estimatedHours: number;
  // For visualization
  constraintStart: Date;
  constraintEnd: Date;
}
```

